import hashlib
import secrets
import string

def generate_salt(length=16):
    return ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(length))

def hash_password(password, salt=None):
    if not salt:
        salt = generate_salt()
    
    hashed_password = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode('utf-8'), 100000)
    return salt + hashed_password

def encrypt_sensitive_data(data):
    encrypted_data = hash_password(data['password'])
    if 'email' in data:
        encrypted_email = hashlib.sha256((data['email'] + encrypted_data).encode()).hexdigest()
        data['email'] = encrypted_email
    if 'phone_number' in data:
        encrypted_phone_number = hashlib.md5((data['phone_number'] + encrypted_data).encode()).hexdigest()
        data['phone_number'] = encrypted_phone_number
    return {'encrypted_password': encrypted_data, **data}

